import { prefix as prfx } from "utils/prefix";
import { classnames } from "utils/classnames";

export function spacing(prefix, spaces, axisX, axisY, top, end, bottom, start) {
  const result = {
    [prfx(`${prefix}x`, axisX)]: axisX,
    [prfx(`${prefix}y`, axisY)]: axisY,
    [prfx(`${prefix}t`, top)]: top,
    [prfx(`${prefix}e`, end)]: end,
    [prfx(`${prefix}b`, bottom)]: bottom,
    [prfx(`${prefix}s`, start)]: start,
  };

  if (typeof spaces === "string" || typeof spaces === "number") {
    return {
      ...result,
      [prfx(prefix, spaces)]: spaces !== null,
    };
  }

  if (typeof spaces === "object") {
    return {
      ...result,
      [classnames(prefix, spaces)]: spaces !== null,
    };
  }
}
